import{_ as i,W as d,X as t,$ as e,a0 as n,a1 as a,Z as l,D as r}from"./framework-805da640.js";const o={},c=e("h2",{id:"简介",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#简介","aria-hidden":"true"},"#"),n(" 简介")],-1),u=e("p",null,[n("背景："),e("br"),n(" 由于本人在内网搭建了不少服务，如文件共享、私有云盘、个人博客等等，然后通过内网穿透将其映射到公网云服务器上，再通过反向代理来访问服务。但是大多数情况下，我还是处在和服务器相同的内网环境下的，每次都从公网访问服务属于绕远路了，因此考虑自建一个内网的DNS解析服务器，将域名直接解析到内网ip上，而当我脱离内网环境时，则可以使用公共DNS继续从公网IP访问服务。")],-1),p={href:"https://www.isc.org/bind/",target:"_blank",rel:"noopener noreferrer"},v={href:"https://thekelleys.org.uk/dnsmasq/doc.html",target:"_blank",rel:"noopener noreferrer"},m=e("p",null,[e("strong",null,"科普：")],-1),h={class:"hint-container tip"},b=e("p",{class:"hint-container-title"},"什么是DNS服务器",-1),S=e("p",null,"DNS（Domain Name System，域名系统）服务器是一种网络服务，用于将域名解析成 IP 地址或者将 IP 地址解析成域名。DNS 服务器是互联网中的重要组成部分，它们负责将域名映射到相应的 IP 地址，实现网络通信。",-1),N=e("p",null,"DNS 服务器通常分为递归 DNS 服务器和权威 DNS 服务器两种类型。递归 DNS 服务器是用于向客户端提供 DNS 解析服务，它会根据客户端的请求逐级向上查询 DNS 记录，直到找到所需的解析记录或者查询失败。权威 DNS 服务器则存储特定域名的 DNS 记录，它会为请求该域名的客户端提供相应的解析记录。",-1),D=e("p",null,"DNS 服务器按照数据分布方式可分为以下几种类型：",-1),g=e("li",null,[e("p",null,"根 DNS 服务器（Root DNS Server）：是 DNS 系统的顶级 DNS 服务器，存储了所有顶级域名（如 .com、.org、.net 等）的权威 DNS 服务器的 IP地址。根 DNS 服务器的数量很少，通常由 13 台服务器组成。")],-1),_={href:"http://google.com",target:"_blank",rel:"noopener noreferrer"},f={href:"http://apple.com",target:"_blank",rel:"noopener noreferrer"},k=e("li",null,[e("p",null,"权威 DNS 服务器（Authoritative DNS Server）：存储特定域名的 DNS 记录，为请求该域名的客户端提供相应的解析记录。")],-1),q=e("li",null,[e("p",null,"本地 DNS 服务器（Local DNS Server）：也称为递归 DNS 服务器，通常位于本地网络中，为本地网络的客户端提供 DNS 解析服务。本地 DNS 服务器会逐级向上查询 DNS 记录，直到找到所需的解析记录或者查询失败。如果本地 DNS 服务器无法找到所需的解析记录，则会向其他递归 DNS 服务器发出查询请求。")],-1),x=l("<p>DNS 服务器的工作原理通常分为以下几个步骤：</p><ol><li><p>客户端向本地 DNS 服务器发送DNS 查询请求，请求解析指定的域名。</p></li><li><p>如果本地 DNS 服务器已经缓存了请求的 DNS 记录，则直接返回缓存中的记录。否则，本地 DNS 服务器会向根 DNS 服务器发送查询请求，请求根 DNS 服务器返回顶级域名服务器的 IP 地址。</p></li><li><p>根 DNS 服务器会将请求转发给相应的顶级域名服务器，顶级域名服务器会返回该域名的权威 DNS 服务器的 IP 地址。</p></li><li><p>本地 DNS 服务器向权威 DNS 服务器发出查询请求，请求返回该域名的 DNS 记录。</p></li><li><p>权威 DNS 服务器返回请求的 DNS 记录给本地 DNS 服务器。</p></li><li><p>本地 DNS 服务器将 DNS 记录缓存起来，并将解析结果返回给客户端。</p></li></ol><p>总之，DNS 服务器是实现域名解析的核心组件之一，负责将域名映射到相应的 IP 地址或者将 IP 地址解析成域名。在互联网中，DNS 服务器的分布和数量是非常多样化的，这些 DNS 服务器相互协作，构成了一个庞大的 DNS 系统。</p>",3),y=l(`<div class="hint-container tip"><p class="hint-container-title">递归DNS服务器和权威DNS服务器的区别</p><p>递归 DNS 服务器（Recursive DNS Server）和权威 DNS 服务器（Authoritative DNS Server）是两种不同的 DNS 服务器类型，它们的主要区别如下：</p><ul><li><p>功能不同：递归 DNS 服务器用于向客户端提供 DNS 解析服务，它会根据客户端的请求逐级向上查询 DNS 记录，直到找到所需的解析记录或者查询失败。而权威 DNS 服务器则存储特定域名的 DNS 记录，它会为请求该域名的客户端提供相应的解析记录。</p></li><li><p>数据来源不同：递归 DNS 服务器在查询 DNS 记录时，会从其他 DNS 服务器中逐级向上查询，直到找到所需的解析记录。而权威 DNS 服务器则直接存储特定域名的 DNS 记录，它是该域名 DNS 记录的最终来源。</p></li><li><p>所在位置不同：递归 DNS 服务器通常位于本地网络中，为本地网络的客户端提供 DNS 解析服务。而权威 DNS 服务器则通常由域名注册商或者网站管理员管理，用于存储特定域名的 DNS 记录。</p></li><li><p>接受查询的方式不同：递归 DNS 服务器通常接受来自本地网络中的客户端的 DNS 查询请求，然后向其他 DNS 服务器发出查询请求，最终返回所需的 DNS 记录。而权威 DNS 服务器只接受来自其他 DNS 服务器的查询请求，在查询到所需的 DNS 记录后，会将其返回给发出查询请求的 DNS 服务器。</p></li></ul><p>总之，递归 DNS 服务器和权威 DNS 服务器都是 DNS 系统中不可缺少的组成部分，但其作用和功能不同。递归 DNS 服务器主要为客户端提供 DNS 解析服务，而权威 DNS 服务器则存储特定域名的 DNS 记录，并为请求该域名的客户端提供相应的解析记录。</p></div><h2 id="dnsmasq安装与使用" tabindex="-1"><a class="header-anchor" href="#dnsmasq安装与使用" aria-hidden="true">#</a> dnsmasq安装与使用</h2><h3 id="安装" tabindex="-1"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">apt-get</span> update
<span class="token function">sudo</span> <span class="token function">apt-get</span> <span class="token function">install</span> dnsmasq
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="使用" tabindex="-1"><a class="header-anchor" href="#使用" aria-hidden="true">#</a> 使用</h3><p>配置文件路径：<code>/etc/dnsmasq.conf</code></p><p>重要参数说明：</p>`,7),I=e("thead",null,[e("tr",null,[e("th",null,"名称"),e("th",null,"含义")])],-1),P=e("tr",null,[e("td",null,"resolv-file"),e("td",null,[n("指定上游DNS服务器文件的路径，默认为"),e("code",null,"/etc/resolv.dnsmasq.conf")])],-1),w=e("tr",null,[e("td",null,"strict-order"),e("td",null,[n("默认情况下，dnsmasq 查询上游 DNS 服务器时采用的是并行查询的方式，即同时向所有的上游 DNS 服务器发送 DNS 查询请求，并使用最先收到的响应结果作为查询结果。"),e("br"),n("当 strict-order 参数被设置为 true 时，dnsmasq 将按照配置文件中指定的顺序查询上游 DNS 服务器，即先查询第一个 DNS 服务器，如果没有响应或者响应超时，则查询第二个 DNS 服务器，以此类推。")])],-1),z=e("tr",null,[e("td",null,"interface"),e("td",null,"指定监听的网卡，默认监听所有，可以使用多个interface参数来指定")],-1),L=e("tr",null,[e("td",null,"listen-address"),e("td",null,"指定监听的ip地址，局域网使用填写内网ip")],-1),B=e("tr",null,[e("td",null,"server"),e("td",null,[n("指定dnsmasq使用的上游 DNS 服务器地址,可以使用多个server参数来指定,如"),e("code",null,"server=/taobao.com/223.5.5.5")])],-1),V=e("td",null,"address",-1),A=e("code",null,"address=/example.com/192.168.0.2",-1),E={href:"http://example.com",target:"_blank",rel:"noopener noreferrer"},C=e("tr",null,[e("td",null,"no-resolv"),e("td",null,"禁用系统的 /etc/resolv.conf 文件，并使用 dnsmasq 的上游 DNS 服务器")],-1),F=e("tr",null,[e("td",null,"no-hosts"),e("td",null,"用于控制是否使用系统的 /etc/hosts 文件。当 no-hosts 参数被设置为 true 时，dnsmasq 将不使用系统的 /etc/hosts 文件，而是仅使用其他来源（例如上游 DNS 服务器）提供的 DNS 记录来解析主机名。")],-1),R=e("tr",null,[e("td",null,"addn-hosts"),e("td",null,"用于指定额外的 DNS 记录。当 addn-hosts 参数被设置时，dnsmasq 将从指定的文件中读取额外的 DNS 记录，并将其添加到本地 DNS 缓存中，以提供更准确和定制化的 DNS 解析服务。")],-1),T=l(`<p>推荐配置：</p><ul><li><code>/etc/dnsmasq.conf</code>：dnsmasq配置文件</li></ul><div class="language-conf line-numbers-mode" data-ext="conf"><pre class="language-conf"><code>resolv-file=/etc/resolv.dnsmasq.conf
strict-order
# 本机使用只加环回IP，全网使用需要在环回后加本机IP
listen-address=192.168.1.106,127.0.0.1

# 为域名配置指定dns
# server=/taobao.com/223.5.5.5

# 为域名配置指定ip(相当于dns劫持)
# address=/example.com/192.168.0.2

# 1)不使用通配符
# address=/app.kevin2li.top/192.168.1.106

# 2)使用通配符解析 *.kevin2li.top
# address=/.kevin2li.top/192.168.1.106

# 开启日志(debug时可以用)
# log-queries

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>/etc/resolv.dnsmasq.conf</code>： 配置上游DNS服务器</li></ul><div class="language-conf line-numbers-mode" data-ext="conf"><pre class="language-conf"><code># 阿里
nameserver 223.5.5.5
nameserver 223.6.6.6

# 114
nameserver 114.114.114.114
nameserver 114.114.115.115

# 谷歌
nameserver 8.8.8.8
nameserver 8.8.4.4
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>/etc/resolv.conf</code>：默认<code>systemd-resolvd</code>配置文件</li></ul><div class="language-conf line-numbers-mode" data-ext="conf"><pre class="language-conf"><code># 只保留下面这一个，删除其他的nameserver(保证解析请求从dnsmasq走)
nameserver 127.0.0.1
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>修改完配置后，重启：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> systemctl restart dnsmasq
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>本机验证：</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230524205136.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><div class="hint-container tip"><p class="hint-container-title">与\`systemd-resolvd\`冲突？</p><p>可以关闭<code>systemd-resolvd</code>:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 停止</span>
<span class="token function">sudo</span> systemctl stop systemd-resolvd

<span class="token comment"># 关闭开机自启</span>
<span class="token function">sudo</span> systemctl disable systemd-resolvd
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></div><p>为了让局域网其他设备也使用dnsmasq服务器解析域名，可以手动修改设备的dns地址，也可以直接在路由器DHCP设置中指定dns地址，这样连接上的设备会自动设置好dns。</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230524221335.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="faq" tabindex="-1"><a class="header-anchor" href="#faq" aria-hidden="true">#</a> FAQ</h3><ol><li>查看域名查询日志</li></ol><p>在<code>/etc/dnsmasq.conf</code>中加入</p><div class="language-conf line-numbers-mode" data-ext="conf"><pre class="language-conf"><code># For debugging purposes, log each DNS query as it passes through dnsmasq.
log-queries
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>重启：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> systemctl restart dnsmasq
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>查看：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">less</span> /var/log/syslog <span class="token operator">|</span> <span class="token function">grep</span> dnsmasq 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230524220053.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ol start="2"><li>局域网设备设置dns为dnsmasq服务器ip后后无法解析域名</li></ol><p>一般由于服务器防火墙拦截导致，可以通过下面命令放行dnsmasq服务：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> firewall-cmd <span class="token parameter variable">--permanent</span> <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --add-port <span class="token number">53</span>/udp <span class="token comment"># 一定要加(实测)</span>
<span class="token function">sudo</span> firewall-cmd <span class="token parameter variable">--permanent</span> <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --add-port <span class="token number">53</span>/tcp
<span class="token function">sudo</span> firewall-cmd <span class="token parameter variable">--reload</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h3>`,27),H={href:"https://blog.xiaoz.org/archives/8303",target:"_blank",rel:"noopener noreferrer"},Q={href:"https://blog.niekun.net/archives/1869.html",target:"_blank",rel:"noopener noreferrer"};function W(X,Z){const s=r("ExternalLinkIcon");return d(),t("div",null,[c,u,e("p",null,[n("目前主流的内网DNS服务器软件主要有"),e("a",p,[n("BIND"),a(s)]),n("和"),e("a",v,[n("dnsmasq"),a(s)]),n("，前者功能强大完备，通常被用于大型企业，比较重量级，而后者适用于小型网络、家庭网络等场景，比较轻量化,比较适合我目前的需求。因此，本文主要介绍dnsmasq的安装与使用方法。")]),m,e("div",h,[b,S,N,D,e("ul",null,[g,e("li",null,[e("p",null,[n("顶级域名服务器（Top-Level Domain DNS Server）：是权威 DNS 服务器的一种，负责管理顶级域名（如 .com、.org、.net 等）下的所有二级域名（如 "),e("a",_,[n("google.com"),a(s)]),n("、"),e("a",f,[n("apple.com"),a(s)]),n(" 等）的 DNS 记录。")])]),k,q]),x]),y,e("table",null,[I,e("tbody",null,[P,w,z,L,B,e("tr",null,[V,e("td",null,[n("为指定的主机名指定 IP 地址, 例如，可以使用 "),A,n(" 将 "),e("a",E,[n("example.com"),a(s)]),n(" 域名解析为 192.168.0.2。")])]),C,F,R])]),T,e("ol",null,[e("li",null,[e("a",H,[n("Linux安装DNSmasq搭建自己的公共DNS"),a(s)])]),e("li",null,[e("a",Q,[n("dnsmasq 使用教程"),a(s)])])])])}const j=i(o,[["render",W],["__file","自建内网DNS解析服务器.html.vue"]]);export{j as default};
